tests:
def test_basic():
    result = alien_order(['wrt', 'wrf', 'er', 'ett', 'rftt'])
    assert result == 'wertf'

def test_two_words():
    result = alien_order(['z', 'x'])
    assert result == 'zx'

def test_single_word():
    result = alien_order(['abc'])
    assert set(result) == {'a', 'b', 'c'}
    assert len(result) == 3

def test_two_same_words():
    result = alien_order(['abc', 'abc'])
    assert set(result) == {'a', 'b', 'c'}
    assert len(result) == 3

def test_single_char_words():
    result = alien_order(['z', 'z'])
    assert result == 'z'
